import{_ as a,o as n,c as r,a3 as t}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"42. Remuneration And Remuneration Increases","description":"","frontmatter":{"title":"42. Remuneration And Remuneration Increases","eba":"Doctors in Training 2022-2026","topics":["wages","preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/remuneration/42-remuneration-and-remuneration-increases.md","filePath":"ebas/doctors-in-training/remuneration/42-remuneration-and-remuneration-increases.md"}'),o={name:"ebas/doctors-in-training/remuneration/42-remuneration-and-remuneration-increases.md"};function s(i,e,c,l,p,h){return n(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="_42-remuneration-and-remuneration-increases" tabindex="-1">42. Remuneration And Remuneration Increases <a class="header-anchor" href="#_42-remuneration-and-remuneration-increases" aria-label="Permalink to &quot;42. Remuneration And Remuneration Increases&quot;">​</a></h1><p><strong>42.1</strong> Weekly rates of pay will be increased by the amounts set out below:</p><p><strong>(a)</strong> 2.75% from the first pay period commencing on or after 1 March 2022;</p><p><strong>(b)</strong> 2.5% from the first pay period commencing on or after 1 September 2023;</p><p><strong>(c)</strong> 2.5% from the first pay period commencing on or after 1 March 2025;</p><p><strong>42.2</strong> The increases in rates of pay and other monetary entitlements specified in this Agreement have been agreed on the understanding that they will be the increases actually paid to the Doctors during the life of this Agreement. Where a Doctor’s remuneration has been negotiated as an annualised salary, the increase will apply to this annualised rate.</p><p><strong>42.3</strong> Existing work-related allowances will increase in accordance with the salary increases in subclause 42.1 above.</p><p><strong>42.4</strong> The weekly rates of pay and allowances for the life of this Agreement are set out in <a href="/eba/ebas/doctors-in-training/appendices/2-doctors-in-training-remuneration-allowances-and-deductions.html">Appendix 2</a>.</p><p><strong>42.5</strong> The increases in subclause 42.1 will not apply to private practice bonuses except where these have been included in a rolled up or annualised salary arrangement.</p><p><strong>42.6</strong> Patience in bargaining payment</p><p>At the commencement of this Agreement, all Doctors will receive a once off lump sum payment of 2.5% of their ordinary wages calculated between 1 January 2022 and 28 February 2022.</p><p><strong>42.7</strong> Other matters</p><p><strong>(a)</strong> Doctors must be paid the rate of pay consistent with their correct classification prescribed in <a href="/eba/ebas/doctors-in-training/appendices/2-doctors-in-training-remuneration-allowances-and-deductions.html">Appendix 2</a>.</p><p><strong>(b)</strong> Unless subclause (c) applies, the correct classification and rate of pay of a Doctor is based on that Doctor’s years of experience as defined at subclause 3.1(m) (Experience).</p><p><strong>(c)</strong> Where a Doctor has been appointed by a Health Service as a Registrar the Doctor will progress annually through the incremental pay scale of the Registrar classification from his or her date of commencing work as a Registrar; provided that, where a Registrar moves from one recognised Specialty stream to another, he or she will not progress to the next higher annual incremental level for a further period of 12 months (refer subclause 3.1(bb)).</p><p><strong>(d)</strong> Where a Doctor has performed duty that entitles that Doctor to more than one penalty, only the penalty of the higher value will be payable. For the purposes of this clause, ‘penalty’ also means overtime payable pursuant to <a href="/eba/ebas/doctors-in-training/hours-of-work/36-overtime.html">clause 36</a>.</p><p><strong>(e)</strong> Penalties must be applied to wages but not to allowances.</p><p>Plain language terms: pay, pay rise, salary increase.</p>',18)])])}const u=a(o,[["render",s]]);export{d as __pageData,u as default};
